// Filter financing events for Seed and Series A rounds within the last 7 days
const items = $input.all();
const results = [];
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

for (const item of items) {
  const events = item.json.data || item.json.financing_events || [];
  const domain = item.json.domain || item.json.company_domain || 'unknown';

  for (const event of events) {
    const roundType = (event.attributes?.category || event.category || '').toLowerCase();
    const eventDate = new Date(event.attributes?.date || event.date || '1970-01-01');

    if (
      (roundType.includes('seed') || roundType.includes('series_a') || roundType.includes('series a')) &&
      eventDate >= sevenDaysAgo
    ) {
      results.push({
        json: {
          domain: domain,
          company_name: event.attributes?.company_name || event.company_name || domain,
          round_type: event.attributes?.category || event.category || 'Unknown',
          amount: event.attributes?.amount || event.amount || 'Undisclosed',
          currency: event.attributes?.currency || event.currency || 'USD',
          date: event.attributes?.date || event.date || 'Unknown',
          investors: (event.attributes?.investors || event.investors || []).join(', ') || 'Undisclosed'
        }
      });
    }
  }
}

// If no results, pass an empty marker
if (results.length === 0) {
  return [{ json: { _no_results: true } }];
}

return results;

// Aggregate all filtered financing events into a single array
const items = $input.all();
const allEvents = [];

for (const item of items) {
  if (!item.json._no_results) {
    allEvents.push(item.json);
  }
}

if (allEvents.length === 0) {
  return [{
    json: {
      summary: 'No new Seed or Series A rounds found in the last 7 days from your watchlist.',
      events: [],
      count: 0
    }
  }];
}

return [{
  json: {
    summary: `Found ${allEvents.length} Seed/Series A round(s) in the last 7 days.`,
    events: allEvents,
    count: allEvents.length
  }
}];

